   654→      {/* === RECAP STATE === */}
   655→      {recapData && (
   656→        <SessionRecap
   657→          summary={recapData.summary}
   658→          likedItems={recapData.liked_items || []}
   659→          stats={recapData.stats}
   660→          userName={recapData.user_name}
   661→          onDismiss={handleRecapDismiss}
   662→        />
   663→      )}
   664→
   665→      {/* Error indicators */}
   666→      {(cameraError || modelError) && (
   667→        <div
   668→          style={{
   669→            position: "absolute",
